 9→        queryKey: ['postReactions', journalId],
10→        queryFn: () => getPostReactions(journalId),
11→        enabled: !!journalId,
12→        staleTime: 1000 * 60 * 2,
13→        refetchOnWindowFocus: false,
14→    });
15→
16→    const reactions = data?.reactions || [];
17→
18→    if (reactions.length === 0) return null;
19→
20→    return (
21→        <div className="reaction-summary">
