  1→import { useEffect, useRef, useState } from 'react';
  2→import './comments.css'
  3→import { motion } from "framer-motion";
  4→import { addComment } from '../../../API/Api';
  5→import { useAuth } from '../../Context/useAuth';
  6→import { getComments } from '../../../API/Api';
  7→import { useInfiniteQuery, useQueryClient } from '@tanstack/react-query';
  8→import { BarLoader, MoonLoader } from 'react-spinners';
  9→import CommentsCards from './commentsCards';
 10→
 11→const incrementJournalCommentCount = (old, postId) => {
 12→    if (!old || !Array.isArray(old.pages)) return old;
 13→
 14→    return {
 15→        ...old,
 16→        pages: old.pages.map((page) => ({
 17→            ...page,
 18→            data: Array.isArray(page?.data)
 19→                ? page.data.map((journal) => {
 20→                    if (journal?.id !== postId) return journal;
 21→
 22→                    const currentCount = journal?.comment_count?.[0]?.count ?? 0;
 23→                    return {
 24→                        ...journal,
 25→                        comment_count: [{ count: currentCount + 1 }],
 26→                    };
 27→                })
 28→                : page?.data,
 29→        })),
 30→    };
 31→};
 32→
 33→const CommentSection = ({onclose, postId, receiverId})=>{
 34→    const queryClient = useQueryClient();
 35→
 36→    const {session, user} = useAuth();
 37→
 38→    const textAreaFocusRef = useRef();
 39→
 40→    const [comments, setComments] = useState('');
 41→    const [isSubmittingComment, setIsSubmittingComment] = useState(false);
 42→
 43→    const {data, fetchNextPage, hasNextPage, isLoading, isFetchingNextPage} = useInfiniteQuery({
 44→        queryKey: ['postComments', postId],
 45→        queryFn: ({queryKey, pageParam = null}) => getComments(pageParam, 10, queryKey[1]),
 46→        getNextPageParam: (lastPage) => {
 47→            if(lastPage?.hasMore) {
 48→                const lastComment = lastPage.comments[lastPage?.comments?.length - 1];
 49→                return new Date(lastComment.created_at).toISOString();
 50→            } else {
 51→                return undefined;
 52→            }
 53→        },
 54→        refetchOnWindowFocus: false,
 55→        staleTime: 1000 * 60 * 5
 56→    })
 57→
 58→    const handleSeeMoreComments = (e) =>{
 59→        e.stopPropagation();
 60→        if(hasNextPage && !isFetchingNextPage){
 61→            try {
 62→                fetchNextPage()
 63→            } catch (error) {
 64→                throw new Error(error);
 65→            }
 66→        }
 67→    }
 68→
 69→    useEffect(() =>{
 70→        let timeout;
 71→        if(textAreaFocusRef.current){
 72→            timeout = setTimeout(() => {
 73→                textAreaFocusRef.current.focus();
 74→            }, 500);
 75→        }
 76→        return () => {
 77→             clearTimeout(timeout);
 78→        }
 79→    }, [])
 80→
 81→    const handeCloseCommentsSection = (e) =>{
 82→        e.stopPropagation();
 83→        onclose()
 84→    }
 85→
 86→    const handaleSubmitComment = async(e, postId, receiverId) =>{
 87→        e.stopPropagation();
 88→        const trimmedComment = comments.trim();
 89→        if (!trimmedComment) return;
 90→
 91→        const optimisticComment = {
 92→            id: `optimistic-${Date.now()}`,
 93→            comment: trimmedComment,
 94→            created_at: new Date().toISOString(),
 95→            parent_id: null,
 96→            post_id: postId,
 97→            reply_count: 0,
 98→            user_id: user?.userData?.[0]?.id,
 99→            users: {
100→                id: user?.userData?.[0]?.id,
101→                name: user?.userData?.[0]?.name,
102→                image_url: user?.userData?.[0]?.image_url,
103→                badge: user?.userData?.[0]?.badge,
104→            },
105→        };
106→
107→        queryClient.cancelQueries({ queryKey: ['postComments', postId] });
108→        const previousComments = queryClient.getQueryData(['postComments', postId]);
109→        const previousJournalCaches = [
110→            ...queryClient.getQueriesData({ queryKey: ['journals'] }),
111→            ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
112→            ...queryClient.getQueriesData({ queryKey: ['visitedProfileJournals'] }),
113→        ];
114→
115→        queryClient.setQueryData(['postComments', postId], (old) => {
116→            if (!old || !Array.isArray(old.pages)) {
117→                return {
118→                    pageParams: [null],
119→                    pages: [{ comments: [optimisticComment], hasMore: false }],
120→                };
121→            }
122→
123→            return {
124→                ...old,
125→                pages: old.pages.map((page, index) =>
126→                    index === 0
127→                        ? { ...page, comments: [optimisticComment, ...(page?.comments || [])] }
128→                        : page
129→                ),
130→            };
131→        });
132→
133→        queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => incrementJournalCommentCount(old, postId));
134→        queryClient.setQueriesData({ queryKey: ['userJournals'] }, (old) => incrementJournalCommentCount(old, postId));
135→        queryClient.setQueriesData({ queryKey: ['visitedProfileJournals'] }, (old) => incrementJournalCommentCount(old, postId));
136→
137→        const body = {
138→            comments: trimmedComment,
139→            postId: postId,
140→            receiverId: receiverId,
141→        }
142→
143→        try {
144→            setIsSubmittingComment(true)
145→            const message = await addComment(session?.access_token, body);
146→            if(message){
147→                // console.log(message)
148→            }
149→            // Only refetch this post's comments — feed comment counts were
150→            // already updated optimistically via setQueriesData above.
151→            queryClient.invalidateQueries({ queryKey: ['postComments', postId] });
152→        } catch (error) {
153→            queryClient.setQueryData(['postComments', postId], previousComments);
154→            previousJournalCaches.forEach(([key, value]) => {
155→                queryClient.setQueryData(key, value);
156→            });
157→            throw new Error('error adding comments')
158→        } finally {
159→            setIsSubmittingComment(false)
160→            setComments('')
161→        }
162→    }
163→
164→    const commentsData = data?.pages?.flatMap((page) => page.comments || []);
165→
166→    return(
167→        <motion.div
168→            initial={{y: '100vh', opacity: 0}}
169→            animate={{
170→                y: 0,
171→                opacity: 1,
172→                transition: {type: 'spring', damping: 25, stiffness: 200}
173→            }}
174→            exit={{y: '-100vh', opacity: 0, transition: {duration: 0.2}}}
175→            className="cm-parent-container"
176→        >
177→            <div className="cm-header">
178→                <p className="cm-header-title">Comments</p>
179→                <div className="cm-close-btn" onClick={(e) => handeCloseCommentsSection(e)}>
180→                    <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px">
181→                        <path d="m336-280-56-56 144-144-144-143 56-56 144 144 143-144 56 56-144 143 144 144-56 56-143-144-144 144Z"/>
182→                    </svg>
183→                </div>
184→            </div>
185→
186→            <div className="cm-list">
187→                {isLoading ? (
188→                    <div className="cm-loading">
189→                        <MoonLoader color='rgba(19, 77, 104, 1)' size={20} loading={isLoading}/>
190→                    </div>
191→                ) : (
192→                    commentsData?.map((comment, index) => (
193→                        <CommentsCards postId={postId} key={comment?.id || index} comments={comment}/>
194→                    ))
195→                )}
196→
197→                {hasNextPage && (
198→                    <button onClick={(e) => handleSeeMoreComments(e)} className="cm-load-more">
199→                        See more comments
200→                        {isFetchingNextPage && (<MoonLoader size={12} speedMultiplier={0.5} color='rgba(19, 77, 104, 1)'/>)}
201→                    </button>
202→                )}
203→            </div>
204→
205→            <div className="cm-input-area">
206→                <div className="cm-input-row">
207→                    <textarea
208→                        ref={textAreaFocusRef}
209→                        value={comments}
210→                        onChange={(e) => setComments(e.target.value)}
211→                        className="cm-textarea"
212→                        maxLength={200}
213→                        placeholder="Write a comment..."
214→                        rows={1}
215→                    />
216→                    <button
217→                        disabled={isSubmittingComment || !comments.trim()}
218→                        onClick={(e) => handaleSubmitComment(e, postId, receiverId)}
219→                        className="cm-submit-btn"
220→                    >
221→                        Submit
222→                    </button>
223→                </div>
224→                <div className="cm-action-row">
225→                    <p className={`cm-char-count ${comments.length > 199 ? 'cm-char-limit' : ''}`}>
226→                        {comments.length}/200
227→                    </p>
228→                </div>
229→            </div>
230→
231→            {isSubmittingComment && (
232→                <div className="cm-progress">
233→                    <BarLoader loading={isSubmittingComment} width={'100%'} color="rgb(40, 115, 255)" speedMultiplier={0.9}/>
234→                </div>
235→            )}
236→        </motion.div>
237→    )
238→}
239→
240→export default CommentSection;
