  1→import { useEffect, useRef, useState } from "react"
  2→import { useAuth } from "../../Context/useAuth";
  3→import { MoonLoader } from "react-spinners";
  4→import { addReply, getPostReplies } from "../../../API/Api";
  5→import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
  6→import { handleClickProfile } from "../../../helpers/handleClicks";
  7→import { useNavigate } from "react-router-dom";
  8→import { motion, AnimatePresence } from "framer-motion";
  9→import VerifiedBadge from "../Badge/VerifiedBadge";
 10→import formatPostDate from "../../../helpers/formatDateString";
 11→
 12→const incrementReplyCount = (old, parentId) => {
 13→    if (!old || !Array.isArray(old.pages)) return old;
 14→
 15→    return {
 16→        ...old,
 17→        pages: old.pages.map((page) => ({
 18→            ...page,
 19→            comments: Array.isArray(page?.comments)
 20→                ? page.comments.map((comment) => {
 21→                    if (comment?.id !== parentId) return comment;
 22→                    return {
 23→                        ...comment,
 24→                        reply_count: (comment?.reply_count || 0) + 1,
 25→                    };
 26→                })
 27→                : page?.comments,
 28→        })),
 29→    };
 30→};
 31→
 32→
 33→const CommentsCards = ({comments, postId}) =>{
 34→    const {user, session} = useAuth();
 35→    const userId = user?.userData[0].id;
 36→    const queryClient = useQueryClient();
 37→
 38→    const [showReplyInput, setShowReplyInput] = useState(false);
 39→    const [showReplies, setShowReplies] = useState(false);
 40→
 41→    const [reply, setReply] = useState('')
 42→    const [replyLoaderId, setReplyLoaderId] = useState('');
 43→
 44→    const navigate = useNavigate();
 45→    const replyInputRef = useRef(null);
 46→
 47→    const clickProfile = handleClickProfile(navigate);
 48→
 49→    const {data, isLoading, fetchNextPage, hasNextPage, isFetchinNextPage} = useInfiniteQuery({
 50→        queryKey: ['getPostReplies', comments.id],
 51→        queryFn: ({pageParam = null, queryKey}) => getPostReplies(queryKey[1], 5, pageParam),
 52→        getNextPageParam: (lastPage) => {
 53→            if(lastPage.hasMore){
 54→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 55→                return lastReply.id;
 56→            } else{
 57→                return undefined
 58→            }
 59→        },
 60→        refetchOnWindowFocus: false,
 61→        enabled: showReplies,
 62→        staleTime: 1000 * 60 * 5
 63→    })
 64→
 65→    const handleClickReplyButton = (e) =>{
 66→        e.stopPropagation();
 67→        setShowReplyInput(!showReplyInput);
 68→    }
 69→
 70→    const handleShowMoreReplies = () => {
 71→        if(!isFetchinNextPage){
 72→            fetchNextPage();
 73→        }
 74→    }
 75→
 76→    const submitReply = async(parent_id, receiver_id) => {
 77→        const trimmedReply = reply.trim();
 78→        if (!trimmedReply) return;
 79→
 80→        setReplyLoaderId(parent_id)
 81→        queryClient.cancelQueries({ queryKey: ['getPostReplies', parent_id] });
 82→        queryClient.cancelQueries({ queryKey: ['postComments', postId] });
 83→
 84→        const previousReplies = queryClient.getQueryData(['getPostReplies', parent_id]);
 85→        const previousComments = queryClient.getQueryData(['postComments', postId]);
 86→
 87→        const optimisticReply = {
 88→            id: `optimistic-reply-${Date.now()}`,
 89→            post_id: postId,
 90→            parent_id: parent_id,
 91→            comment: trimmedReply,
 92→            created_at: new Date().toISOString(),
 93→            user_id: user?.userData?.[0]?.id,
 94→            users: {
 95→                id: user?.userData?.[0]?.id,
 96→                name: user?.userData?.[0]?.name,
 97→                image_url: user?.userData?.[0]?.image_url,
 98→                badge: user?.userData?.[0]?.badge,
 99→            },
100→            reply_count: 0,
101→        };
102→
103→        queryClient.setQueryData(['getPostReplies', parent_id], (old) => {
104→            if (!old || !Array.isArray(old.pages)) {
105→                return {
106→                    pageParams: [null],
107→                    pages: [{ data: [optimisticReply], hasMore: false }],
108→                };
109→            }
110→
111→            return {
112→                ...old,
113→                pages: old.pages.map((page, index) =>
114→                    index === 0
115→                        ? { ...page, data: [optimisticReply, ...(page?.data || [])] }
116→                        : page
117→                ),
118→            };
119→        });
120→        queryClient.setQueryData(['postComments', postId], (old) => incrementReplyCount(old, parent_id));
121→
122→        try {
123→            const formdata = new FormData();
124→            formdata.append('reply', trimmedReply);
125→
126→            const message = await addReply(userId, postId, parent_id, formdata, receiver_id, session?.access_token);
127→            if(message){
128→                // console.log(message);
129→            }
130→            queryClient.invalidateQueries({ queryKey: ['getPostReplies', parent_id] });
131→            queryClient.invalidateQueries({ queryKey: ['postComments', postId] });
132→            setReply('')
133→            setShowReplies(true)
134→        } catch (error) {
135→            queryClient.setQueryData(['getPostReplies', parent_id], previousReplies);
136→            queryClient.setQueryData(['postComments', postId], previousComments);
137→            setReply('')
138→            throw new Error('error adding replies')
139→        } finally {
140→            setReplyLoaderId('')
