 96→    let path = `/journals/search?query=${encodeURIComponent(q)}&limit=${limit}`;
 97→    if (userId) path += `&userId=${encodeURIComponent(userId)}`;
 98→    return publicGet(path, 'failed to search journals');
 99→};
