  1→import { useInfiniteQuery, useQueryClient } from "@tanstack/react-query";
  2→import { addReplyOpinion, getOpinionReply } from "../../../API/Api";
  3→import { useState, useRef } from "react";
  4→import { useAuth } from "../../Context/useAuth";
  5→import { motion, AnimatePresence } from "framer-motion";
  6→import formatPostDate from "../../../helpers/formatDateString";
  7→import VerifiedBadge from "../Badge/VerifiedBadge";
  8→
  9→const MAX_VISUAL_DEPTH = 4;
 10→
 11→const OpinionsReplyCard = ({ opinionId, depth = 0 }) => {
 12→    const queryClient = useQueryClient();
 13→    const { user, session } = useAuth();
 14→
 15→    const [showReply, setShowReply] = useState(false);
 16→    const [replyOpinion, setReplyOpinion] = useState('');
 17→    const [isTypingId, setIsTypingId] = useState('');
 18→    const [showReplyButtonId, setShowReplyButtonId] = useState('');
 19→
 20→    const textAreaRef = useRef(null);
 21→
 22→    const { data, isLoading, hasNextPage, isFetchingNextPage, fetchNextPage } = useInfiniteQuery({
 23→        queryKey: ['getReplyOpinion', opinionId],
 24→        queryFn: ({ queryKey, pageParam = null }) => getOpinionReply(queryKey[1], 10, pageParam),
 25→        getNextPageParam: (lastPage) => {
 26→            if (lastPage?.hasMore) {
 27→                const lastReply = lastPage?.data[lastPage?.data.length - 1];
 28→                return lastReply.id;
 29→            }
 30→            return undefined;
 31→        },
 32→        enabled: !!opinionId,
 33→        refetchOnWindowFocus: false,
 34→        staleTime: 1000 * 60 * 5
 35→    });
 36→
 37→    const handleSubmitReplyOpinion = async (reply, receiver_id, sender_id, parent_id) => {
 38→        try {
 39→            const formadata = new FormData();
 40→            formadata.append('opinion', reply);
 41→            await addReplyOpinion(formadata, receiver_id, sender_id, parent_id, session?.access_token);
 42→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 43→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 44→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion'] });
 45→            setReplyOpinion('');
 46→            if (textAreaRef.current) {
 47→                textAreaRef.current.innerText = '';
 48→            }
 49→        } catch (error) {
 50→            console.error(error);
 51→            setReplyOpinion('');
 52→            if (textAreaRef.current) {
 53→                textAreaRef.current.innerText = '';
 54→            }
 55→            queryClient.invalidateQueries({ queryKey: ['getReplyOpinion', opinionId] });
 56→            queryClient.invalidateQueries({ queryKey: ['getOpinions'] });
 57→            queryClient.invalidateQueries({ queryKey: ['getViewOpinion'] });
 58→        }
 59→    };
 60→
 61→    const cancelTyping = () => {
 62→        setIsTypingId('');
 63→        setReplyOpinion('');
 64→        if (textAreaRef.current) {
 65→            textAreaRef.current.innerText = '';
 66→            textAreaRef.current.blur();
 67→        }
 68→        setShowReplyButtonId('');
 69→    };
 70→
 71→    const visualDepth = Math.min(depth, MAX_VISUAL_DEPTH);
 72→    const opinioData = data?.pages.flatMap((page) => page.data) || [];
 73→
 74→    return (
 75→        <div
 76→            className="rc-thread"
 77→            style={{ '--depth': visualDepth }}
 78→        >
 79→            {opinioData?.map((opinion, index) => (
 80→                <motion.div
 81→                    className="so-card-wrapper rc-card"
 82→                    key={opinion.id}
 83→                    initial={{ opacity: 0, y: 6 }}
 84→                    animate={{ opacity: 1, y: 0 }}
 85→                    transition={{ duration: 0.25, delay: index * 0.03, ease: "easeOut" }}
 86→                >
 87→                    {depth > 0 && <div className="rc-thread-line" />}
 88→
 89→                    <div className="so-card so-card--flat">
 90→                        <div className="so-card-content">
 91→                            <div className="so-user-row">
 92→                                <div className="so-user-meta">
 93→                                    <div className={`so-avatar-outer ${opinion.users?.badge === 'legend' ? 'avatar-ring-legend' : opinion.users?.badge === 'og' ? 'avatar-ring-og' : ''}`}>
 94→                                        <img
 95→                                            className="so-avatar"
 96→                                            src={opinion.users?.image_url || '../assets/profile.jpg'}
 97→                                            alt={`${opinion?.users?.name || "User"} profile picture`}
 98→                                        />
 99→                                    </div>
100→                                    <div className="so-name-block">
101→                                        <div className="so-name-line">
102→                                            <span className="so-username">{opinion.users?.name}</span>
103→                                            <VerifiedBadge badge={opinion.users?.badge} size={14}/>
104→                                        </div>
105→                                        <span className="so-handle">{formatPostDate(opinion.created_at)}</span>
106→                                    </div>
107→                                </div>
108→                            </div>
109→
110→                            <div className="so-body">
111→                                {opinion.opinion}
112→                            </div>
113→
114→                            <div className="so-meta-bar">
115→                                {opinion.reply_count > 0 && (
116→                                    <span
117→                                        className="so-reply-pill"
118→                                        onClick={() => setShowReply(prev => !prev)}
119→                                    >
120→                                        <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
121→                                            <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
122→                                        </svg>
123→                                        {showReply ? 'Hide' : 'Show'} {opinion.reply_count} {opinion.reply_count === 1 ? 'reply' : 'replies'}
124→                                    </span>
125→                                )}
126→                                <span
127→                                    className="so-reply-pill"
128→                                    onClick={() => setShowReplyButtonId(
129→                                        showReplyButtonId === opinion.id ? '' : opinion.id
130→                                    )}
131→                                >
132→                                    <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
133→                                        <polyline points="9 17 4 12 9 7" />
134→                                        <path d="M20 18v-2a4 4 0 0 0-4-4H4" />
135→                                    </svg>
136→                                    Reply
137→                                </span>
138→                            </div>
139→
140→                            <AnimatePresence>
141→                                {showReplyButtonId === opinion.id && (
142→                                    <motion.div
143→                                        initial={{ height: 0, opacity: 0 }}
144→                                        animate={{ height: "auto", opacity: 1 }}
145→                                        exit={{ height: 0, opacity: 0 }}
146→                                        transition={{ duration: 0.2 }}
147→                                        className="rc-reply-input-wrapper"
148→                                    >
149→                                        <div
150→                                            className="ov-reply-input"
151→                                            onFocus={() => setIsTypingId(opinion.id)}
152→                                            ref={textAreaRef}
153→                                            onInput={(e) => setReplyOpinion(e.currentTarget.innerText.trim())}
154→                                            data-placeholder={`Add a reply to '${opinion.users?.name}'`}
155→                                            contentEditable="true"
156→                                            role="textbox"
157→                                        />
158→
159→                                        {isTypingId === opinion.id && (
160→                                            <div className="ov-btn-row">
161→                                                <button onClick={cancelTyping} className="ov-btn-cancel">Cancel</button>
162→                                                <button
163→                                                    disabled={replyOpinion.trim().length === 0}
164→                                                    onClick={() => handleSubmitReplyOpinion(replyOpinion, opinion.users.id, user?.userData[0].id, opinion.id)}
165→                                                    className={`ov-btn-submit ${replyOpinion.trim().length === 0 ? 'ov-btn-disabled' : ''}`}
166→                                                >
167→                                                    Submit
168→                                                </button>
169→                                            </div>
170→                                        )}
171→                                    </motion.div>
172→                                )}
173→                            </AnimatePresence>
174→
175→                            <AnimatePresence>
176→                                {showReply && (
177→                                    <motion.div
178→                                        initial={{ opacity: 0 }}
179→                                        animate={{ opacity: 1 }}
180→                                        exit={{ opacity: 0 }}
181→                                        transition={{ duration: 0.2 }}
182→                                    >
183→                                        <OpinionsReplyCard opinionId={opinion.id} depth={depth + 1} />
184→                                    </motion.div>
185→                                )}
186→                            </AnimatePresence>
187→                        </div>
188→                    </div>
189→                </motion.div>
190→            ))}
191→
192→            {hasNextPage && (
193→                <button className="rc-load-more" onClick={() => fetchNextPage()}>
194→                    {isFetchingNextPage ? 'Loading...' : 'Show more replies'}
195→                </button>
196→            )}
197→        </div>
198→    );
199→};
200→
201→export default OpinionsReplyCard;
